import React, { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { Trophy, Info } from 'lucide-react';
import { analyticsApi } from '../api/analytics';
import Card from './Card';

const METRICS = [
  { key: 'registered_onboarded', label: 'Registered Onboarded' },
  { key: 'linked_accounts', label: 'Linked Accounts' },
  { key: 'total_advance_applications', label: 'Total Advance Applications' },
  { key: 'total_advance_applicants', label: 'Total Advance Applicants' },
  { key: 'total_micro_financing_applications', label: 'Total Micro Financing Applications' },
  { key: 'total_micro_financing_applicants', label: 'Total Micro Financing Applicants' },
  { key: 'total_personal_finance_application', label: 'Total Personal Finance Application' },
  { key: 'total_personal_finance_applicants', label: 'Total Personal Finance Applicants' }
];

const BestMonthAnalysis: React.FC = () => {
  const [selectedMetric, setSelectedMetric] = useState('total_advance_applicants');
  const [selectedWeeks, setSelectedWeeks] = useState('all');
  const [showTooltip, setShowTooltip] = useState(false);

  const { data, isLoading, error } = useQuery({
    queryKey: ['best-month', selectedMetric, selectedWeeks],
    queryFn: () => analyticsApi.getBestMonth({
      metric: selectedMetric,
      weeks: selectedWeeks
    })
  });

  const chartData = data?.scores?.map((score: any) => ({
    month: score.month,
    score: score.score,
    value: score.value,
    rank: score.rank
  })) || [];

  return (
    <Card title="Best Month Analysis">
      <div className="space-y-6">
        {/* Metric Selector */}
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">
            Select Metric
          </label>
          <select
            value={selectedMetric}
            onChange={(e) => setSelectedMetric(e.target.value)}
            className="w-full p-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500"
          >
            {METRICS.map(metric => (
              <option key={metric.key} value={metric.key}>
                {metric.label}
              </option>
            ))}
          </select>
        </div>

        {/* Week Selection */}
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">
            Include Weeks
          </label>
          <div className="flex flex-wrap gap-2">
            {['all', '1', '2', '3', '4', '5'].map(week => (
              <button
                key={week}
                onClick={() => setSelectedWeeks(week)}
                className={`px-3 py-1 rounded-full text-sm font-medium transition-colors ${
                  selectedWeeks === week
                    ? 'bg-blue-500 text-white'
                    : 'bg-gray-200 text-gray-700 hover:bg-gray-300'
                }`}
              >
                {week === 'all' ? 'All Weeks' : `Week ${week}`}
              </button>
            ))}
          </div>
        </div>

        {/* Results */}
        {isLoading && (
          <div className="flex justify-center py-8">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-500"></div>
          </div>
        )}

        {error && (
          <div className="bg-red-50 border border-red-200 rounded-md p-4">
            <p className="text-red-800">Error loading data: {(error as Error)?.message || 'Unknown error'}</p>
          </div>
        )}

        {data && data.scores && data.scores.length > 0 ? (
          <div className="space-y-6">
            {/* Winner Card */}
            {data.winner && (
              <div className="bg-gradient-to-r from-yellow-50 to-yellow-100 border border-yellow-200 rounded-lg p-6">
                <div className="flex items-center space-x-3 mb-4">
                  <Trophy className="h-8 w-8 text-yellow-600" />
                  <div>
                    <h3 className="text-xl font-bold text-yellow-800">
                      Winner: {data.winner.month}
                    </h3>
                    <p className="text-yellow-700">
                      Score: {data.winner.score} | Value: {data.winner.value.toLocaleString()}
                    </p>
                  </div>
                  <div className="ml-auto relative">
                    <button
                      onMouseEnter={() => setShowTooltip(true)}
                      onMouseLeave={() => setShowTooltip(false)}
                      className="text-yellow-600 hover:text-yellow-800"
                    >
                      <Info className="h-5 w-5" />
                    </button>
                    {showTooltip && (
                      <div className="absolute right-0 top-6 bg-gray-900 text-white text-xs rounded py-2 px-3 whitespace-nowrap z-10">
                        {data.explain?.notes}
                      </div>
                    )}
                  </div>
                </div>
              </div>
            )}

            {/* Chart */}
            <div className="h-64">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={chartData}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis dataKey="month" />
                  <YAxis />
                  <Tooltip 
                    formatter={(value: any, name: string) => [
                      name === 'score' ? `${value} (Score)` : value.toLocaleString(),
                      name === 'score' ? 'Score' : 'Value'
                    ]}
                    labelFormatter={(label) => `Month: ${label}`}
                  />
                  <Bar 
                    dataKey="score" 
                    fill="#3B82F6"
                    name="score"
                  />
                </BarChart>
              </ResponsiveContainer>
            </div>

            {/* Ranking Table */}
            <div className="overflow-x-auto">
              <table className="min-w-full divide-y divide-gray-200">
                <thead className="bg-gray-50">
                  <tr>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      Rank
                    </th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      Month
                    </th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      Score
                    </th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      Value
                    </th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      Badge
                    </th>
                  </tr>
                </thead>
                <tbody className="bg-white divide-y divide-gray-200">
                  {data.scores.map((score: any) => (
                    <tr key={score.month} className={score.rank === 1 ? 'bg-yellow-50' : ''}>
                      <td className="px-6 py-4 whitespace-nowrap">
                        <span className={`inline-flex items-center justify-center w-6 h-6 rounded-full text-xs font-medium ${
                          score.rank === 1 ? 'bg-yellow-500 text-white' :
                          score.rank === 2 ? 'bg-gray-400 text-white' :
                          score.rank === 3 ? 'bg-orange-400 text-white' :
                          'bg-gray-200 text-gray-600'
                        }`}>
                          {score.rank}
                        </span>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                        {score.month}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                        <div className="flex items-center space-x-2">
                          <span>{score.score}</span>
                          <div className="w-16 bg-gray-200 rounded-full h-2">
                            <div 
                              className="bg-blue-500 h-2 rounded-full"
                              style={{ width: `${score.score * 100}%` }}
                            ></div>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                        {score.value.toLocaleString()}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap">
                        {score.rank === 1 && (
                          <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-yellow-100 text-yellow-800">
                            🏆 Best
                          </span>
                        )}
                        {score.rank === 2 && (
                          <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-gray-100 text-gray-800">
                            🥈 Runner-up
                          </span>
                        )}
                        {score.rank === 3 && (
                          <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-orange-100 text-orange-800">
                            🥉 Third
                          </span>
                        )}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            {/* Scoring Explanation */}
            {data.explain && (
              <div className="bg-gray-50 p-4 rounded-md">
                <h4 className="font-medium text-gray-900 mb-2">Scoring Method</h4>
                <div className="text-sm text-gray-600 space-y-1">
                  <p><strong>Method:</strong> {data.explain.method}</p>
                  <p><strong>Weights:</strong> Volume ({data.explain.weights.volume * 100}%), Stability ({data.explain.weights.stability * 100}%)</p>
                  <p><strong>Formula:</strong> {data.explain.notes}</p>
                </div>
              </div>
            )}
          </div>
        ) : (
          !isLoading && (
            <div className="text-center py-8">
              <p className="text-gray-500 mb-4">No data available for analysis</p>
              <button className="bg-blue-500 text-white px-4 py-2 rounded-md hover:bg-blue-600">
                Go to Data Entry
              </button>
            </div>
          )
        )}
      </div>
    </Card>
  );
};

export default BestMonthAnalysis;
